  1→import React, { useEffect, useState, useRef } from "react";
  2→import { MoonLoader } from "react-spinners";
  3→import { motion, AnimatePresence,} from "framer-motion";
  4→import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
  5→import './postcards.css';
  6→import { getJournals, searchJournals } from "../../../../API/Api";
  7→import ParseContent from "./parseData";
  8→import { useInView } from 'react-intersection-observer';
  9→import CalculateText from "./calculateReadingTime";
 10→import { useLocation, useNavigate, useOutletContext } from "react-router-dom";
 11→import VerifiedBadge from "../../Badge/VerifiedBadge";
 12→
 13→import { useAuth } from "../../../Context/useAuth";
 14→import { useAddViewsMutation, useBookMarkMutation, useLikeMutation } from "../../../utils/useMutation";
 15→import formatCounts from "../../../../helpers/fomatCounts";
 16→import debounce from "../../../../helpers/debounce";
 17→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
 18→import formatPostDate from "../../../../helpers/formatDateString";
 19→import { handleImageFallback } from "../../../utils/handleImageFallback";
 20→import { getCanvasPreview } from "../../../utils/canvasDoc";
 21→import CanvasPreview from "./CanvasPreview/CanvasPreview";
 22→
 23→
 24→const PostCards = () => {
 25→    const {session, user, openAuthModal} = useAuth();
 26→    const location = useLocation();
 27→    const outletContext = useOutletContext() || {};
 28→    const { clickOpenSidebar, handleOpenTextEditor } = outletContext;
 29→
 30→    const navigate = useNavigate();
 31→    const modalRef = useRef(null);
 32→    const searchShellRef = useRef(null);
 33→    const timeOutRef = useRef();
 34→    const {ref, inView} = useInView({
 35→        threshold: 0,
 36→        rootMargin: '800px'
 37→    })
 38→    const [postIdSettings, setPostIdSettings] = useState('');
 39→    const [showHeaders, setShowHeaders] = useState(true);
 40→
 41→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 42→    const [showBookmarkedMessage, setShowBookmarkedMessage] = useState(null);
 43→    const [searchInput, setSearchInput] = useState('');
 44→    const [debouncedSearchInput, setDebouncedSearchInput] = useState('');
 45→    const [committedSearchQuery, setCommittedSearchQuery] = useState('');
 46→    const [isSearchFocused, setIsSearchFocused] = useState(false);
 47→
 48→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 49→    const clickContent = handleCLickContent(navigate);
 50→
 51→    const mutateViews = useAddViewsMutation(session)
 52→
 53→    const handleClickUserProfile = (e, loggedInUserId, clickedUserId) => {
 54→        e.stopPropagation();
 55→        if(!session){
 56→            return openAuthModal();
 57→        }
 58→        handleClickUserProfileOriginal(e, loggedInUserId, clickedUserId);
 59→    }
 60→
 61→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) =>{
 62→        e.stopPropagation();
 63→        if(!session){
 64→            return openAuthModal();
 65→        }
 66→        const formadata = new FormData();
 67→
 68→        formadata.append('journalId', journalId);
 69→        mutateViews.mutate(formadata);
 70→
 71→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc )
 72→    }
 73→
 74→    const header_links = [
 75→        {label: 'Writings', path: '/home'},
 76→        {label: 'Opinions', path: '/home/opinions'},
 77→    ]
 78→
 79→    const handleClickHeaderLinks = (path) =>{
 80→        navigate(path);
 81→    }
 82→
 83→    const handleExpandCanvas = (e, journal) => {
 84→        e.stopPropagation();
 85→        viewContent(
 86→            e,
 87→            journal.content,
 88→            getCanvasPreview(journal?.canvas_doc)?.wholeText || '',
 89→            journal.title,
 90→            journal.users.id,
 91→            journal.users.name,
 92→            journal.users.image_url,
 93→            journal.created_at,
 94→            journal.id,
 95→            journal.has_liked,
 96→            journal.comment_count?.[0]?.count,
 97→            journal.has_bookmarked,
 98→            journal.like_count?.[0]?.count,
 99→            journal.bookmark_count?.[0]?.count,
100→            journal.users.badge,
101→            journal?.post_type,
102→            journal?.canvas_doc
103→        );
104→    }
105→
106→    const handleRemixCanvas = (e, journal) => {
107→        e.stopPropagation();
108→        if(!session){
109→            openAuthModal();
110→            return;
111→        }
112→
113→        const sourceTitle = typeof journal?.title === 'string' ? journal.title.trim() : '';
114→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
115→            ? sourceTitle
116→            : `Remix: ${sourceTitle || 'Canvas'}`;
117→
118→        navigate('/home', {
119→            state: {
120→                openEditor: true,
121→                editorMode: 'canvas',
122→                initialTitle: remixTitle,
123→                initialCanvasDoc: journal?.canvas_doc || null,
124→                remixSource: {
125→                    journalId: journal?.id,
126→                    authorName: journal?.users?.name || 'Unknown'
127→                }
128→            }
129→        });
130→    }
131→
132→    const cardIcons = [
133→        {
134→            likeAction: (isLiked) => (
135→                <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
136→                    <g id="style=fill">
137→                    <g id="like">
