602→export const getJournalsService = async(limit, userId, before) => {
603→    if(isNaN(limit) || limit > 20 || limit < 1){
604→        console.error('limit should be intiger, not below 1 and higher than 20');
605→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
606→    }
607→
608→    const parsedLimit = parseInt(limit);
609→
610→    let query = supabase
611→    .from('journals')
612→    .select(`
613→        *, users(*),
614→        like_count: likes(count),
615→        comment_count: comments(count),
616→        bookmark_count: bookmarks(count)
617→        `)
618→    .eq('privacy', 'public')
619→    .order('created_at', {ascending: false})
620→    .order('id', {ascending: false})
621→    .limit(parsedLimit + 1);
622→
623→    if(before){
624→        query = query.lt('created_at', before);
625→    }
626→
627→    const {data, error} = await query;
628→
629→    if(error){
630→        console.error('supabase error while fetching journals:', error.message);
631→        throw{status: 500, error: 'supabase error while fetching journals'}
632→    }
633→
634→    if(data.length === 0){
635→        const journalData = {
636→            data: [],
637→            hasMore: false
638→        }
639→        return journalData
640→    }
641→
642→    // If userId is provided, fetch personalization (likes/bookmarks)
643→    // Otherwise return journals with has_liked/has_bookmarked defaulting to false
644→    let userHasLikedSet = new Set();
645→    let userHasBookmarkedSet = new Set();
646→
647→    if(userId){
648→        const journalIds = data.map((journal) => journal.id);
649→
650→        const [userLikes, userBookmarks] = await Promise.all([
651→            supabase
652→            .from('likes')
653→            .select('journal_id')
654→            .in('journal_id', journalIds)
655→            .eq('user_id', userId),
656→
657→            supabase
658→            .from('bookmarks')
659→            .select('journal_id')
660→            .in('journal_id', journalIds)
661→            .eq('user_id', userId)
662→        ]);
663→
664→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
665→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
666→
667→        if(errorUserLikeResult || errorUserBookmarksResult) {
668→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
669→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
670→        }
671→
672→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
673→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
674→    }
675→
676→    const formattedData = data?.map((journal) => ({
677→        ...journal,
678→        has_liked: userHasLikedSet.has(journal.id),
679→        has_bookmarked: userHasBookmarkedSet.has(journal.id)
680→    }))
681→
682→    const hasMore = data?.length > parsedLimit;
683→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
684→
685→    const journalData = {
686→        data: slicedData,
687→        hasMore: hasMore
688→    }
689→    return journalData;
690→}
