  4→const POST_TYPE_CANVAS = 'canvas';
  5→
  6→const extractCanvasPlainText = (canvasDoc) => {
  7→    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
  8→        return '';
  9→    }
 10→
 11→    return canvasDoc.snippets
 12→        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 13→        .filter(Boolean)
 14→        .join(' ');
