 17→const assertCanvasJournalAccess = async(journalId, viewerId = null) => {
 18→    if(!journalId){
 19→        throw {status: 400, error: 'journalId is undefined'};
 20→    }
 21→
 22→    const {data: journal, error: journalError} = await supabase
 23→    .from('journals')
 24→    .select('id, user_id, title, post_type, canvas_doc, privacy')
 25→    .eq('id', journalId)
 26→    .maybeSingle();
 27→
 28→    if(journalError){
 29→        console.error('supabase error while fetching canvas journal', journalError.message);
 30→        throw {status: 500, error: 'supabase error while fetching canvas journal'};
 31→    }
 32→
 33→    if(!journal){
 34→        throw {status: 404, error: 'journal not found'};
 35→    }
 36→
 37→    if(journal.post_type !== POST_TYPE_CANVAS){
 38→        throw {status: 400, error: 'journal is not a canvas post'};
 39→    }
 40→
 41→    const isOwner = viewerId && journal.user_id === viewerId;
 42→    if(journal.privacy === 'private' && !isOwner){
 43→        throw {status: 403, error: 'canvas journal is private'};
 44→    }
 45→
 46→    return journal;
 47→}
